import{_ as t,o as r,c as a,ag as o}from"./chunks/framework.Culc7SYV.js";const c=JSON.parse('{"title":"About LearnKit","description":"","frontmatter":{},"headers":[],"relativePath":"Support-LearnKit.md","filePath":"Support-LearnKit.md","lastUpdated":1773877710000}'),i={name:"Support-LearnKit.md"};function n(l,e,s,u,p,h){return r(),a("div",null,[...e[0]||(e[0]=[o('<h1 id="about-learnkit" tabindex="-1">About LearnKit <a class="header-anchor" href="#about-learnkit" aria-label="Permalink to &quot;About LearnKit&quot;">ŌĆŗ</a></h1><h2 id="our-story" tabindex="-1">Our Story <a class="header-anchor" href="#our-story" aria-label="Permalink to &quot;Our Story&quot;">ŌĆŗ</a></h2><p>LearnKit was built by William Guy, a final-year medical student in New Zealand, to bring modern spaced-repetition directly into your Obsidian vault. Flashcards are at the heart of LearnKit, but the goal is bigger: to be the memory layer for Obsidian - linking your notes to review, recall, and long-term retention in one system.</p><p>LearnKit is proudly open source and will always remain free. No hidden fees. No subscriptions. Learning tools should not lock your knowledge behind paywalls, and your notes and data should stay entirely under your control.</p><p>Companion, the AI companion introduced in LearnKit 1.1.0, runs on a bring-your-own API key model. You choose which provider to use and pay only for what you use, not a fixed monthly fee set by us.</p><p><img src="https://raw.githubusercontent.com/ctrlaltwill/LearnKit/main/site/branding/Founder.jpg" alt="William Guy"></p><ul><li><a href="https://www.linkedin.com/in/williamguy/" target="_blank" rel="noreferrer">Find out more about Will</a></li></ul><h2 id="feedback-issues" tabindex="-1">Feedback &amp; Issues <a class="header-anchor" href="#feedback-issues" aria-label="Permalink to &quot;Feedback &amp; Issues&quot;">ŌĆŗ</a></h2><p>Found a bug? Have an idea for a feature? We&#39;d love to hear from you. LearnKit uses GitHub issue templates to keep things organised ŌĆö just pick the right one and fill it in.</p><ul><li><a href="https://github.com/ctrlaltwill/LearnKit/issues/new?template=bug_report.yml" target="_blank" rel="noreferrer">Report a bug</a></li><li><a href="https://github.com/ctrlaltwill/LearnKit/issues/new?template=feature_request.yml" target="_blank" rel="noreferrer">Request a feature</a></li><li><a href="https://github.com/ctrlaltwill/LearnKit/issues" target="_blank" rel="noreferrer">Browse open issues</a></li></ul><h2 id="support-the-project" tabindex="-1">Support the Project <a class="header-anchor" href="#support-the-project" aria-label="Permalink to &quot;Support the Project&quot;">ŌĆŗ</a></h2><p>You can support LearnKit by starring the repo, sharing it with friends, or sponsoring development. Because LearnKit is open source, the goal is simple: powerful learning tools without paywalls.</p><ul><li><a href="https://github.com/ctrlaltwill/LearnKit" target="_blank" rel="noreferrer">ŌŁÉ Star on GitHub</a></li><li><a href="https://github.com/ctrlaltwill/LearnKit" target="_blank" rel="noreferrer">­¤ōŗ Share LearnKit</a></li><li><a href="https://buymeacoffee.com/williamguy" target="_blank" rel="noreferrer">ŌØż’ĖÅ Sponsor development</a></li></ul>',13)])])}const b=t(i,[["render",n]]);export{c as __pageData,b as default};
